class ParkingSystem {
public:
    ParkingSystem(int big, int medium, int small) {
        bigSpace = big;
        mediumSpace = medium;
        smallSpace = small;
    }

    bool addCar(int carType) {
        switch (carType) {
            case 1: return bigSpace-- > 0;
            case 2: return mediumSpace-- > 0;
            case 3: return smallSpace-- > 0;
            default: return false;
        }
    }
private:
    int bigSpace;
    int mediumSpace;
    int smallSpace;
};
```
